const u=$input.first().json;
let chatId,type,text,callbackData,callbackQueryId;
if(u.callback_query){
  type='callback';
  chatId=u.callback_query.message?.chat?.id;
  callbackQueryId=u.callback_query.id;
  callbackData=u.callback_query.data;
  // Boton 'Alta Probabilidad' del menu => menu de ligas
  if(callbackData==='__alta__'){
    type='command';
    text='/alta';
    callbackData='';
  }
  // Seleccion de liga especifica => escanear esa liga
  if(callbackData&&callbackData.startsWith('alta:')){
    type='command';
    text='/alta '+callbackData.substring(5); // '/alta soccer_fifa_world_cup'
    callbackData='';
  }
}else{
  type='command';
  chatId=u.message?.chat?.id;
  text=u.message?.text||'';
}
return[{json:{type,chatId:String(chatId||''),text:text||'',callbackData:callbackData||'',callbackQueryId:callbackQueryId||''}}];

const ctx=$('Extraer Contexto').first().json;
const chatId=ctx.chatId;
const cmdText=(ctx.text||'').trim().toLowerCase();

// ============================================================
// SECCION: ALTA PROBABILIDAD  
// Filosofia: el modelo manda, el mercado da el precio.
// Solo apostamos cuando nuestro modelo ve MAS prob que el mercado.
// EV = prob_modelo * mejor_cuota - 1  → positivo = tenemos ventaja
// FASE 1: Bloqueo de correlación intra-partido implementado
// ============================================================
if(cmdText==='/alta'||cmdText.startsWith('/alta ')){
  const ODDS_KEY='66ce87d7f976181db2383c4b59716840';

  const TODAS_LIGAS=[
    {id:'soccer_fifa_world_cup',        label:'🌐 Copa 2026 (WC)',    flag:'🌐'},
    {id:'soccer_argentina_primera_division', label:'🇦🇷 Argentina 1ra', flag:'🇦🇷'},
    {id:'soccer_brazil_campeonato',     label:'🇧🇷 Brasileirao A',  flag:'🇧🇷'},
    {id:'soccer_brazil_serie_b',        label:'🇧🇷 Brasil Serie B',  flag:'🇧🇷'},
    {id:'soccer_peru_primera_division', label:'🇵🇪 Peru Liga 1',    flag:'🇵🇪'},
    {id:'soccer_usa_usl_championship',  label:'🇺🇸 USL Championship',flag:'🇺🇸'},
    {id:'soccer_mexico_ligamx',         label:'🇲🇽 Liga MX',          flag:'🇲🇽'},
    {id:'soccer_iceland_premier',       label:'🇮🇸 Islandia',         flag:'🇮🇸'},
    {id:'soccer_ireland_premier_division',label:'🇮🇪 Irlanda',        flag:'🇮🇪'},
  ];

  if(cmdText==='/alta'){
    const rows=[];
    for(let i=0;i<TODAS_LIGAS.length;i+=2){
      const row=[{text:TODAS_LIGAS[i].label, callback_data:'alta:'+TODAS_LIGAS[i].id}];
      if(TODAS_LIGAS[i+1])row.push({text:TODAS_LIGAS[i+1].label, callback_data:'alta:'+TODAS_LIGAS[i+1].id});
      rows.push(row);
    }
    rows.push([{text:'🌍 Todas las ligas', callback_data:'alta:ALL'}]);
    return[{json:{chatId,
      text:'🔥 ALTA PROBABILIDAD\n━'.repeat(1)+'━'.repeat(19)+'\nSelecciona la liga:',
      reply_markup:{inline_keyboard:rows}
    }}];
  }

  const ligaArg=cmdText.replace('/alta','').trim();
  const ligasAEscanear=ligaArg==='all'||ligaArg===''?
    TODAS_LIGAS:
    TODAS_LIGAS.filter(l=>l.id===ligaArg);

  if(!ligasAEscanear.length)return[{json:{chatId,text:'❌ Liga no reconocida. Usa /alta'}}];

  const now=new Date();
  const from=now.toISOString();
  const to=new Date(now.getTime()+4*24*60*60*1000).toISOString();

  const ELO={
    'argentina':2095,'france':1960,'brazil':1900,'england':1830,'spain':1870,
    'germany':1810,'netherlands':1780,'portugal':1790,'belgium':1700,'croatia':1690,
    'uruguay':1700,'denmark':1670,'switzerland':1660,'mexico':1640,'usa':1620,
    'senegal':1640,'morocco':1660,'japan':1630,'colombia':1620,'south korea':1600,
    'norway':1650,'austria':1670,'poland':1610,'canada':1590,'australia':1570,
    'turkey':1620,'ecuador':1580,'italy':1720,'sweden':1630,'ukraine':1600,
    'river plate':1750,'boca juniors':1730,'racing club':1710,'independiente':1680,
    'atletico mineiro':1700,'flamengo':1720,'palmeiras':1710,'fluminense':1680,
    'botafogo':1660,'sao paulo':1650,'corinthians':1640,'santos':1620,
    'alianza lima':1600,'universitario':1590,'sporting cristal':1580,
    'guadalajara':1650,'club america':1660,'cruz azul':1640,'tigres':1630,
    'monterrey':1620,'pachuca':1600
  };
  function getElo(name){
    const k=(name||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z ]/g,'');
    if(ELO[k])return ELO[k];
    for(const[key,val]of Object.entries(ELO))
      if(k.includes(key.substring(0,5))||key.includes(k.substring(0,5)))return val;
    return 1550;
  }
  function poisson(lambda,k){
    if(lambda<=0)return k===0?1:0;
    let r=Math.exp(-lambda);
    for(let i=1;i<=k;i++)r*=lambda/i;
    return Math.max(0,r);
  }
  function modeloProbs(home,away,liga){
    const e1=getElo(home),e2=getElo(away);
    const diff=e1-e2;
    const avg=liga.includes('world_cup')?1.22:liga.includes('argentina')||liga.includes('brazil')||liga.includes('peru')?1.30:1.25;
    const homeAdv=liga.includes('world_cup')?0:0.10;
    const xg1=Math.max(0.4,avg*(1+diff/500)+homeAdv);
    const xg2=Math.max(0.4,avg*(1-diff/500));
    let p1=0,pd=0,p2=0;
    for(let h=0;h<=7;h++)for(let a=0;a<=7;a++){
      const p=poisson(xg1,h)*poisson(xg2,a);
      if(h>a)p1+=p;else if(h<a)p2+=p;else pd+=p;
    }
    return{p1,pd,p2,xg1,xg2};
  }

  function fairMarketProb(bks,home,away){
    let s1=0,sD=0,s2=0,n=0;
    for(const bk of bks.slice(0,12)){
      const h=(bk.markets||[]).find(m=>m.key==='h2h');
      if(!h)continue;
      const o1=h.outcomes.find(o=>o.name===home)?.price;
      const o2=h.outcomes.find(o=>o.name===away)?.price;
      const oD=h.outcomes.find(o=>o.name==='Draw')?.price;
      if(!o1||!o2)continue;
      s1+=1/o1;s2+=1/o2;if(oD)sD+=1/oD;n++;
    }
    if(!n)return null;
    const t=(s1+s2+sD)/n;
    return{fp1:s1/n/t,fp2:s2/n/t,fpD:sD>0?sD/n/t:0};
  }
  function bestOdds(bks,market,name){
    let best=1.0;
    for(const bk of bks){
      const mk=(bk.markets||[]).find(m=>m.key===market);
      const o=mk?.outcomes?.find(o=>o.name===name)?.price;
      if(o&&o>best)best=o;
    }
    return +best.toFixed(2);
  }

  let allMatches=[];
  const ligas_error=[];
  await Promise.all(ligasAEscanear.map(async lg=>{
    try{
      const r=await $helpers.httpRequest({
        method:'GET',
        url:`https://api.the-odds-api.com/v4/sports/${lg.id}/odds/?apiKey=${ODDS_KEY}&regions=eu,us,uk,au&markets=h2h,doubleChance&oddsFormat=decimal&commenceTimeFrom=${encodeURIComponent(from)}&commenceTimeTo=${encodeURIComponent(to)}`,
      });
      if(Array.isArray(r)&&r.length>0)
        r.forEach(m=>allMatches.push({...m,lgLabel:lg.label,lgFlag:lg.flag,lgId:lg.id}));
    }catch(e){ligas_error.push(lg.label);}
  }));

  const picks_value=[];
  for(const m of allMatches){
    if(!(m.bookmakers||[]).length)continue;
    const fmp=fairMarketProb(m.bookmakers,m.home_team,m.away_team);
    if(!fmp)continue;
    const mod=modeloProbs(m.home_team,m.away_team,m.lgId||'');
    const dt=new Date(m.commence_time);
    const dtStr=dt.toLocaleDateString('es',{weekday:'short',month:'short',day:'numeric'})+' '+dt.toLocaleTimeString('es',{hour:'2-digit',minute:'2-digit'});

    const opciones=[
      {tipo:'local', name:m.home_team, prob_modelo:mod.p1, prob_mercado:fmp.fp1},
      {tipo:'empate', name:'Draw',      prob_modelo:mod.pd, prob_mercado:fmp.fpD},
      {tipo:'visita', name:m.away_team, prob_modelo:mod.p2, prob_mercado:fmp.fp2}
    ];

    for(const op of opciones){
      if(op.prob_modelo<0.45)continue;
      if(op.prob_mercado<0.05)continue;
      const mejorCuota=bestOdds(m.bookmakers,'h2h',op.name);
      if(mejorCuota<=1.05)continue;
      const ev=+(op.prob_modelo*mejorCuota-1).toFixed(4);
      if(ev<=0)continue;
      const edge=+(op.prob_modelo-op.prob_mercado).toFixed(4);
      picks_value.push({
        home:m.home_team,away:m.away_team,
        lg:m.lgLabel,flag:m.lgFlag,
        pick:op.tipo==='empate'?'Empate':(op.tipo==='local'?m.home_team:m.away_team),
        prob_modelo:op.prob_modelo,
        prob_mercado:op.prob_mercado,
        cuota:mejorCuota,
        ev,edge,
        dt:dtStr
      });
      break;
    }
  }

  const seenM=new Map();
  for(const p of picks_value){
    const k=p.home+'|'+p.away;
    if(!seenM.has(k)||p.ev>seenM.get(k).ev)seenM.set(k,p);
  }
  const pool=[...seenM.values()].sort((a,b)=>b.ev-a.ev).slice(0,20);

  const ligaTitulo=ligaArg==='all'?'Todas las ligas':ligasAEscanear[0]?.label;

  if(!pool.length){
    let msg=`🔍 Sin VALUE en ${ligaTitulo} (prox 4 dias).\n`;
    msg+=`Analice ${allMatches.length} partidos.\n`;
    msg+='El mercado tiene ventaja en todos los partidos disponibles ahora.\n';
    if(ligas_error.length)msg+='\n⚠️ Sin respuesta: '+ligas_error.join(', ');
    msg+='\n🔄 /alta para otra liga';
    return[{json:{chatId,text:msg}}];
  }

  // ── FASE 1: Combos con bloqueo de correlación intra-partido ──────────────
  // REGLA CLAVE: nunca combinar picks de equipos que se enfrentan entre sí.
  // Si dos picks comparten algún equipo (home o away), son del MISMO partido
  // y tienen correlación alta (φ>0.30) → multiplicar sus prob es doble conteo.
  // Entre partidos DISTINTOS: φ≈0 → independencia válida → se puede multiplicar.
  function mismoPartido(a, b) {
    return a.home===b.home || a.away===b.away ||
           a.home===b.away || a.away===b.home;
  }

  const combis=[];
  let bloqueados=0;

  // DOBLES
  for(let i=0;i<pool.length;i++){
    for(let j=i+1;j<pool.length;j++){
      // Bloqueo correlación intra-partido (Fase 1)
      if(mismoPartido(pool[i],pool[j])){ bloqueados++; continue; }
      const cuotaT=+(pool[i].cuota*pool[j].cuota).toFixed(2);
      const probT=+(pool[i].prob_modelo*pool[j].prob_modelo);
      const evT=+(probT*cuotaT-1).toFixed(4);
      if(evT<=0||cuotaT<1.35||cuotaT>10)continue;
      combis.push({tipo:'DOBLE',picks:[pool[i],pool[j]],cuota:cuotaT,prob:+(probT*100).toFixed(1),ev:evT});
    }
  }
  // TRIPLES
  for(let i=0;i<pool.length;i++){
    for(let j=i+1;j<pool.length;j++){
      for(let k=j+1;k<pool.length;k++){
        // Verificar que ningún par comparte partido
        if(mismoPartido(pool[i],pool[j])||mismoPartido(pool[i],pool[k])||mismoPartido(pool[j],pool[k])){
          bloqueados++; continue;
        }
        const cuotaT=+(pool[i].cuota*pool[j].cuota*pool[k].cuota).toFixed(2);
        const probT=+(pool[i].prob_modelo*pool[j].prob_modelo*pool[k].prob_modelo);
        const evT=+(probT*cuotaT-1).toFixed(4);
        if(evT<=0||cuotaT<1.45||cuotaT>20)continue;
        combis.push({tipo:'TRIPLE',picks:[pool[i],pool[j],pool[k]],cuota:cuotaT,prob:+(probT*100).toFixed(1),ev:evT});
      }
    }
  }
  combis.sort((a,b)=>b.ev-a.ev);

  let msg=`🔥 ALTA PROBABILIDAD\n${ligaTitulo}\n`+'━'.repeat(20)+'\n';
  msg+=`🔍 Analicé ${allMatches.length} partidos → ${pool.length} con value\n`;
  if(bloqueados>0) msg+=`🛡️ ${bloqueados} combos bloqueados por correlación intra-partido\n`;
  msg+=`📊 Cuotas del mercado como precio, el modelo como decisión.\n`;

  if(combis.length){
    msg+=`\n🔵 COMBINACIONES CON VENTAJA (EV+):\n`;
    combis.slice(0,5).forEach((c,i)=>{
      msg+=`\n${i+1}. ${c.tipo} | ${c.cuota}x | ${c.prob}% prob | EV+${(c.ev*100).toFixed(1)}%\n`;
      c.picks.forEach(p=>{
        const edgePct=+(p.edge*100).toFixed(1);
        msg+=`   ${p.flag} ${p.pick} (${p.cuota}x)\n`;
        msg+=`   └ Modelo: ${(p.prob_modelo*100).toFixed(0)}% | Mercado: ${(p.prob_mercado*100).toFixed(0)}% | Edge: +${edgePct}%\n`;
        msg+=`   └ ${p.home} vs ${p.away} | ${p.dt}\n`;
      });
    });
    msg+='\n━'.repeat(20);
    msg+='\n💡 EV+ = modelo ve más valor que el mercado\n';
    msg+='Busca la mejor cuota disponible en tu app.';
  } else {
    msg+='\n⚠️ Picks con value pero sin combis rentables hoy.\n';
    msg+='Picks individuales con edge:\n\n';
    pool.slice(0,6).forEach((p,i)=>{
      msg+=`${i+1}. ${p.flag} ${p.pick} | ${p.cuota}x | Modelo ${(p.prob_modelo*100).toFixed(0)}% vs Mercado ${(p.prob_mercado*100).toFixed(0)}%\n`;
      msg+=`   ${p.home} vs ${p.away} | ${p.dt}\n`;
    });
    msg+='\nEspera más partidos o prueba otra liga.';
  }

  if(ligas_error.length)msg+='\n\n⚠️ Sin respuesta de: '+ligas_error.join(', ');
  msg+='\n🔄 /alta para cambiar liga';
  return[{json:{chatId,text:msg.substring(0,4000)}}];
}

// ============================================================
// SECCION: MENU PRINCIPAL - partidos desde Supabase predicciones
// ============================================================
// Supabase predicciones — array plano directo
const raw = $input.all().map(i => i.json);
const matches = Array.isArray(raw) ? raw : [];
if(matches.length===0) return[{json:{chatId,text:'⚽ No hay partidos disponibles hoy.\n🔥 /alta para picks en otras ligas | 🔴 /vivo en vivo'}}];
const buttons = matches.map(m => {
  const t1 = m.equipo1 || '';
  const t2 = m.equipo2 || '';
  const hora = m.hora ? ' (' + String(m.hora).substring(0,5) + ')' : '';
  return[{text: t1 + ' vs ' + t2 + hora, callback_data: t1 + '|' + t2 + '|' + (m.fecha || '')}];
});
buttons.push([{text:'🔥 Alta Probabilidad otras ligas',callback_data:'__alta__'}]);
return[{json:{chatId,text:'⚽ Selecciona partido:',reply_markup:{inline_keyboard:buttons}}}];

const item=$input.first()?.json||{};const t1=item.equipo1,t2=item.equipo2;const e1=item.estadisticas?.[t1]||{},e2=item.estadisticas?.[t2]||{};const h2h=item.h2h||{},jug=item.jugadores||{},forma=item.formaActual||{};
function fSt(label,s22,s18){let l='['+label+']\n';l+=s22?.played>0?'WC2022: '+s22.played+'J '+s22.wins+'V'+s22.draws+'E'+s22.losses+'D GF:'+s22.gf+' GC:'+s22.ga+'\n':'WC2022: sin datos\n';l+=s18?.played>0?'WC2018: '+s18.played+'J '+s18.wins+'V'+s18.draws+'E'+s18.losses+'D GF:'+s18.gf+' GC:'+s18.ga+'\n':'WC2018: sin datos\n';return l;}
function fH2H(list,year){return list?.length?list.slice(0,3).map(m=>'  '+year+' '+m.date+': '+m.home+' '+m.score[0]+'-'+m.score[1]+' '+m.away).join('\n'):'';}
function fJug(jugData){if(!jugData)return'';let lines='';const sc26=(jugData.topScorers2026||[]).slice(0,3);if(sc26.length)lines+='  Goles 2026: '+sc26.map(p=>p.nombre+'('+p.goles+'G)').join(', ')+'\n';const q=jugData.calidadEquipo;if(q?.score>0)lines+='  Calidad: '+q.score+'pts\n';return lines;}
function fForma(tn,fd){if(!fd)return'  Sin datos\n';let l='';const st=fd.standing;if(st)l+='  '+st.grupo+' pos.'+st.posicion+': '+st.puntos+'pts '+st.victorias+'V'+st.empates+'E'+st.derrotas+'D GF:'+st.gf+' GC:'+st.gc+'\n';const ult=(fd.ultimos5||[]).slice(0,4);if(ult.length){l+='  Ultimos: '+ult.map(m=>m.resultado+'('+m.marcador+' vs '+m.rival+')').join(' ')+'\n';const bt=ult.filter(m=>{const[a,b]=m.marcador.split('-').map(Number);return a>0&&b>0;}).length;l+='  BTTS: '+bt+'/'+ult.length+'\n';}return l;}
const h2hT=[fH2H(h2h.wc2022,'WC2022'),fH2H(h2h.wc2018,'WC2018')].filter(Boolean).join('\n');
let modeloStr='';
if(item.modelo){
  const mo=item.modelo;
  const conf=(mo.d1||0)+(mo.d2||0)>4?'Alta':(mo.d1||0)+(mo.d2||0)>0?'Media':'Solo Elo';
  modeloStr='BASE MATEMATICA (Poisson+Elo) [Fiabilidad:'+conf+']\n';
  modeloStr+='Goles esperados: '+t1+' λ='+mo.L1+' | '+t2+' λ='+mo.L2+'\n';
  if(mo.gkFactor1!==undefined&&(mo.gkFactor1!==1.0||mo.gkFactor2!==1.0)){
    modeloStr+='  (λ pre-portero: '+t1+' '+mo.L1_preGK+' | '+t2+' '+mo.L2_preGK+')\n';
    modeloStr+='  Portero '+t1+': '+mo.gkNivel1+(mo.gkSavePct1!==null?' ('+Math.round(mo.gkSavePct1*100)+'% saves)':'')+' → factor '+mo.gkFactor1+'\n';
    modeloStr+='  Portero '+t2+': '+mo.gkNivel2+(mo.gkSavePct2!==null?' ('+Math.round(mo.gkSavePct2*100)+'% saves)':'')+' → factor '+mo.gkFactor2+'\n';
  }
  modeloStr+='Elo: '+t1+' '+mo.e1+' pts (fuente: '+(mo.elo_fuente||'hardcoded')+') | '+t2+' '+mo.e2+' pts\n';
  modeloStr+=t1+' gana: '+mo.pW+'%  Empate: '+mo.pD+'%  '+t2+' gana: '+mo.pL+'%\n';
  modeloStr+='Over 2.5: '+mo.pO25+'%  |  BTTS: '+mo.pBTTS+'%\nCheck Elo: '+t1+' '+mo.eloChk+'%\n';
}
let xgbStr='';
if(item.xgb&&!item.xgb.error){const x=item.xgb;xgbStr='\nXGBoost+Poisson (60/40 blend, 45k partidos historicos):\n'+t1+' gana: '+(x.prob_team1*100).toFixed(1)+'%  Empate: '+(x.prob_draw*100).toFixed(1)+'%  '+t2+' gana: '+(x.prob_team2*100).toFixed(1)+'%\nOver 2.5: '+(x.prob_over25*100).toFixed(1)+'%  BTTS: '+(x.prob_btts*100).toFixed(1)+'%\nConfianza XGBoost: '+x.confidence+'\n';}
let oddsStr='';if(item.odds?.ok){const o=item.odds;oddsStr='\nCUOTAS MERCADO ('+o.bks+' casas):\n'+t1+': cuota '+o.o1+' (prob.impl. '+o.p1+'%)\nEmpate: cuota '+o.oD+' (prob.impl. '+o.pD+'%)\n'+t2+': cuota '+o.o2+' (prob.impl. '+o.p2+'%)\n'+(o.oOv?'Over2.5: '+o.oOv+' ('+o.pOv+'%) | Under2.5: '+o.oUn+' ('+o.pUn+'%)\n':'');}
let newsStr='';if(item.noticias?.length){newsStr='\nNOTICIAS (lesiones/bajas):\n'+item.noticias.slice(0,3).map(a=>(a.d?a.d+': ':'')+a.t+(a.r?'\n  '+a.r:'')).join('\n')+'\n';}
let afStr='';if(item.afForm?.f1?.length){afStr='\nFORMA WC2026 (API-Football):\n'+t1+': '+item.afForm.f1.slice(0,3).map(f=>f.r+'('+f.m+' vs '+f.opp+')').join(' ')+'\n'+t2+': '+item.afForm.f2.slice(0,3).map(f=>f.r+'('+f.m+' vs '+f.opp+')').join(' ')+'\n';}
let statsStr='';if(item.afStats){const s1=item.afStats[t1],s2=item.afStats[t2];const hasData=(s1?.cornersAvg!==null&&s1?.cornersAvg!==undefined)||(s2?.cornersAvg!==null&&s2?.cornersAvg!==undefined);if(hasData){statsStr='\nESTADISTICAS WC2026 (promedio por partido):\n';if(s1?.cornersAvg!=null)statsStr+=t1+': Corners '+s1.cornersAvg+' | Tiros '+s1.shotsAvg+' (puerta: '+s1.shotsOTAvg+') | Amarillas '+s1.yellowsAvg+'\n';if(s2?.cornersAvg!=null)statsStr+=t2+': Corners '+s2.cornersAvg+' | Tiros '+s2.shotsAvg+' (puerta: '+s2.shotsOTAvg+') | Amarillas '+s2.yellowsAvg+'\n';if(s1?.cornersAvg!=null&&s2?.cornersAvg!=null){const tc=+(s1.cornersAvg+s2.cornersAvg).toFixed(1);const ty=+(s1.yellowsAvg+s2.yellowsAvg).toFixed(1);statsStr+='Total corners esperados: '+tc+' | Total amarillas: '+ty+'\n';}}}
// === SECCION PORTEROS ===
let gkStr='';
if(item.gkStats){
