// Extraer forma de API Football (r='V'/'E'/'D', m='2-1', opp='Mexico')
function buildForm(afArr){
  const af=Array.isArray(afArr)?afArr:[];
  if(!af.length)return null;
  let wins=0,draws=0,losses=0,gf=0,ga=0;
  for(const f of af){
    const parts=(f.m||'').split('-').map(Number);
    if(parts.length===2&&!isNaN(parts[0])&&!isNaN(parts[1])){gf+=parts[0];ga+=parts[1];}
    if(f.r==='V')wins++;
    else if(f.r==='E')draws++;
    else losses++;
  }
  const played=wins+draws+losses;
  return played>0?{wins,draws,losses,gf,ga,played}:null;
}

