function nm(a,b){if(!a||!b)return false;const n=s=>s.toLowerCase().replace(/[^a-z]/g,'');return n(a)===n(b)||n(a).includes(n(b))||n(b).includes(n(a));}

async function fetchStats(fid){
  try{
    const r=await $helpers.httpRequest({method:'GET',url:'https://v3.football.api-sports.io/fixtures/statistics?fixture='+fid,headers:{'x-apisports-key':AF_KEY},timeout:6000});
    return{fid,data:Array.isArray(r.response)?r.response:[]};
  }catch(e){return{fid,data:[]};}
}

