function getStat(stats,type){const st=(stats||[]).find(s=>s.type===type);const v=st?.value;return(v!=null&&v!=='')?Number(v)||0:null;}

// === TEAM STATS (corners, shots, cards) ===
function calcTeamStats(tn,form){
  const corners=[],shots=[],shotsOT=[],yellows=[],reds=[],fouls=[];
  for(const f of form){
    if(!f.fid||!statsMap[f.fid])continue;
    const td=statsMap[f.fid].find(s=>nm(s.team?.name,tn));
    if(!td)continue;
    const st=td.statistics||[];
    const c=getStat(st,'Corner Kicks'),sh=getStat(st,'Total Shots'),sot=getStat(st,'Shots on Goal');
    const y=getStat(st,'Yellow Cards'),r=getStat(st,'Red Cards'),fo=getStat(st,'Fouls');
    if(c!==null)corners.push(c);if(sh!==null)shots.push(sh);if(sot!==null)shotsOT.push(sot);
    if(y!==null)yellows.push(y);if(r!==null)reds.push(r);if(fo!==null)fouls.push(fo);
  }
  const avg=arr=>arr.length?+(arr.reduce((a,b)=>a+b,0)/arr.length).toFixed(1):null;
  return{cornersAvg:avg(corners),shotsAvg:avg(shots),shotsOTAvg:avg(shotsOT),yellowsAvg:avg(yellows),redsAvg:avg(reds),foulsAvg:avg(fouls),n:form.length};
}

// === GOALKEEPER STATS + gkFactor ===
// gkFactor < 1.0 = portero sobresaliente (reduce goleo rival)
// gkFactor > 1.0 = portero bajo rendimiento (facilita goleo rival)
// WC avg save% ≈ 0.70
function calcGkStats(tn,form){
  const saves=[],goalsConc=[],shotsConcArr=[];
  for(const f of form){
    if(!f.fid||!statsMap[f.fid])continue;
    const myData=statsMap[f.fid].find(s=>nm(s.team?.name,tn));
    const oppData=statsMap[f.fid].find(s=>!nm(s.team?.name,tn));
    if(!myData)continue;
    const mySt=myData.statistics||[];
    const oppSt=oppData?.statistics||[];
    const gkSaves=getStat(mySt,'Goalkeeper Saves');
    const oppSOT=getStat(oppSt,'Shots on Goal');   // tiros rival al arco = trabajo del portero
    const oppGoals=getStat(oppSt,'Goals');           // goles recibidos
    if(gkSaves!==null)saves.push(gkSaves);
    if(oppSOT!==null)shotsConcArr.push(oppSOT);
    if(oppGoals!==null)goalsConc.push(oppGoals);
  }

  if(!saves.length)return{gkFactor:1.0,savePercent:null,avgSaves:null,avgGoalsConc:null,partidosMuestra:0};

  // Ponderar partido mas reciente x2
  const w=saves.map((_,i)=>i===0?2:1);
  const wSaves=saves.reduce((s,v,i)=>s+v*w[i],0);
  const wSOT=shotsConcArr.reduce((s,v,i)=>s+v*w[i],0);
  const wTotal=w.reduce((a,b)=>a+b,0);

  const savePercent=wSOT>0?(wSaves/wSOT):null;
  const avgSaves=+(saves.reduce((a,b)=>a+b,0)/saves.length).toFixed(1);
  const avgGoalsConc=goalsConc.length?+(goalsConc.reduce((a,b)=>a+b,0)/goalsConc.length).toFixed(2):null;

  // WC baseline: 70% save%. Cada pp extra reduce gkFactor en 0.5pp
  // Vozinha vs España: ~7 saves de 7 SOT = 100% → gkFactor = max(0.80, 1.0-(1.0-0.70)*0.5) = 0.85
  // Portero normal 70% → gkFactor = 1.0
  // Portero malo 40% → gkFactor = min(1.08, 1.0+(0.70-0.40)*0.4) = 1.08
  let gkFactor=1.0;
  if(savePercent!==null){
    const delta=savePercent-0.70;
    gkFactor=delta>=0
      ?Math.max(0.80,1.0-delta*0.50)   // buen portero: reduce goles rival
      :Math.min(1.08,1.0-delta*0.40);  // mal portero: aumenta goles rival
    gkFactor=+gkFactor.toFixed(3);
  }

  // Nivel legible
  const nivel=savePercent===null?'sin datos'
    :savePercent>=0.90?'EXCEPCIONAL (>90%)'
    :savePercent>=0.80?'Muy bueno (80-90%)'
    :savePercent>=0.70?'Normal (70-80%)'
    :savePercent>=0.55?'Bajo (55-70%)'
    :'Deficiente (<55%)';

  return{gkFactor,savePercent:savePercent!==null?+savePercent.toFixed(3):null,avgSaves,avgGoalsConc,nivel,partidosMuestra:saves.length};
}

