    const byY = bttsOut&&bttsOut.find(o=>o.name==='Yes');
    const pBF = byY ? impliedProb(byY.price) : pBtts;
    msg = header + '---\nAmbos anotan Si: ' + pct(pBF) + (byY?' (cuota: '+byY.price+')':'') + '\nAmbos anotan No: ' + pct(1-pBF) + '\nxG: ' + t1d+' '+xg1.toFixed(2)+' | '+t2d+' '+xg2.toFixed(2) + '\n---\nPronostico: ' + (pBF>0.5?'Si anotan ambos':'No anotan ambos') + ' ' + src;
    break;
  }
  case 'fg':
    msg = header + '---\nPrimer gol ' + t1d + ': ' + pct(pFg1) + '\nPrimer gol ' + t2d + ': ' + pct(1-pFg1) + '\nxG: ' + xg1.toFixed(2) + ' vs ' + xg2.toFixed(2) + '\n---\nPronostico: ' + (pFg1>0.5?t1d:t2d) + ' anota primero (modelo xG)';
    break;
  case 'tt':
    msg = header + '---\n' + t1d + ' > 0.5 goles: ' + pct(pT1ov) + '\n' + t2d + ' > 0.5 goles: ' + pct(pT2ov) + '\nxG: ' + t1d+' '+xg1.toFixed(2)+' | '+t2d+' '+xg2.toFixed(2) + '\n---\nPronostico: ' + (pT1ov>0.5?t1d+' anota':t1d+' podria no anotar') + ' | ' + (pT2ov>0.5?t2d+' anota':t2d+' podria no anotar');
    break;
  case 'ex':
    msg = header + '---\nTop 5 marcadores probables:\n' + top5.map((s,i)=>(i+1)+'. '+t1d+' '+s.s.split('-')[0]+'-'+s.s.split('-')[1]+' '+t2d+': '+pct(s.p)).join('\n') + '\n---\nPronostico: '+top5[0].s.split('-')[0]+'-'+top5[0].s.split('-')[1]+' (Poisson xG '+xg1.toFixed(1)+'-'+xg2.toFixed(1)+')';
    break;
  case 'h1': {
    const xg1h = xg1*0.45, xg2h = xg2*0.45;
    let ph1=0, phx=0, ph2=0;
    for (let h=0;h<=4;h++) for (let a=0;a<=4;a++) {
      const p = poisson(xg1h,h)*poisson(xg2h,a);
      if (h>a) ph1+=p; else if (h===a) phx+=p; else ph2+=p;
    }
    const th=ph1+phx+ph2;
    msg = header+'---\n1er tiempo '+t1d+': '+pct(ph1/th)+'\n1er tiempo Empate: '+pct(phx/th)+'\n1er tiempo '+t2d+': '+pct(ph2/th)+'\nxG HT est: '+xg1h.toFixed(2)+'-'+xg2h.toFixed(2)+'\n---\nPronostico: '+(phx>ph1&&phx>ph2?'Empate al descanso':(ph1>ph2?t1d+' gana 1er tiempo':t2d+' gana 1er tiempo'));
    break;
  }
  case 'mf': {
    const xg1h=xg1*0.45, xg2h=xg2*0.45;
    let ph1=0,phx=0,ph2=0;
    for (let h=0;h<=4;h++) for (let a=0;a<=4;a++) {
      const p=poisson(xg1h,h)*poisson(xg2h,a);
      if(h>a) ph1+=p; else if(h===a) phx+=p; else ph2+=p;
    }
    const th=ph1+phx+ph2; ph1/=th; phx/=th; ph2/=th;
    const combos = [
      {n:'1/1', p:ph1*p1/(p1+px*0.3)},{n:'1/X', p:ph1*px*0.3},
      {n:'X/1', p:phx*p1*0.5},{n:'X/X', p:phx*px*0.7},
      {n:'X/2', p:phx*p2*0.5},{n:'2/2', p:ph2*p2/(p2+px*0.3)},
      {n:'2/X', p:ph2*px*0.3},{n:'1/2', p:ph1*p2*0.05},{n:'2/1', p:ph2*p1*0.05},
    ].sort((a,b)=>b.p-a.p).slice(0,6);
    const tCombos = combos.reduce((s,c)=>s+c.p,0);
    msg = header+'---\n'+combos.map(c=>c.n+': '+pct(c.p/tCombos)).join('\n')+'\n---\nPronostico: '+combos[0].n+' (modelo HT+FT combinado)';
    break;
  }
  case 'hcp': {
    const spr = spreads&&spreads.find(o=>nameMatch(o.name,favRaw));
    const pHF = spr ? impliedProb(spr.price) : pHcpFav;
    const und = elo1>elo2?t2d:t1d;
    msg = header+'---\nFavorito: '+fav+' (-1 gol)\n'+fav+' cubre -1: '+pct(pHF)+(spr?' (cuota: '+spr.price+')':'')+' \n'+und+' cubre +1: '+pct(1-pHF)+'\n---\nPronostico: '+(pHF>0.5?fav+' -1 AH':und+' +1 AH')+' '+src;
    break;
  }
  case 'cor':
    msg = header+'---\nCorners estimados: '+cornerEst.toFixed(1)+'\nMas de 9.5 corners: '+pct(pCor95)+'\nMenos de 9.5 corners: '+pct(1-pCor95)+'\nIntensidad xG: '+xgTot.toFixed(2)+'\n---\nPronostico: '+(pCor95>0.5?'Mas de 9.5 corners':'Menos de 9.5 corners')+' (modelo estadistico WC)';
    break;

  case 'combo': {
    let pOv15c=0, pUn45c=0;
    for (let h=0;h<=8;h++) for (let a=0;a<=8;a++) {
      const p=poisson(xg1,h)*poisson(xg2,a);
      if(h+a>1) pOv15c+=p;
      if(h+a<5) pUn45c+=p;
    }
    const pUn35c=1-pOv35;
    const isFav1=p1A>=p2A;
    const favWinProb=Math.max(p1A,p2A);
    const favWinName=isFav1?t1d+' gana':t2d+' gana';
    const dnbFavProb=Math.max(p1dnb,p2dnb);
    const dnbFavName=p1dnb>p2dnb?t1d+' DNB':t2d+' DNB';

    // BK=0.87 → margen ~13%, mas realista para mercados exoticos
    const BK=0.87;
    const eOdds=p=>Math.max(1.07,(1/Math.max(0.02,p))*BK);

    // Obtener mejor cuota real del Odds API para picks con mercado conocido
    function bestOddsForPick(code, prob) {
      if(code==='favwin'&&h2h){const tName=isFav1?team1Raw:team2Raw;const o=h2h.find(x=>nameMatch(x.name,tName));if(o&&o.price>1.07)return o.price;}
      if(code==='ov25'&&totals){const o=totals.find(x=>x.name==='Over'&&Math.abs((x.point||2.5)-2.5)<0.1);if(o&&o.price>1.07)return o.price;}
      if(code==='ov15'&&totals){const o=totals.find(x=>x.name==='Over'&&Math.abs((x.point||1.5)-1.5)<0.1);if(o&&o.price>1.07)return o.price;}
      if(code==='dc12'){const dcMkt=getOutcomes('doubleChance');if(dcMkt){const o=dcMkt.find(x=>x.name==='12');if(o&&o.price>1.07)return o.price;}}
      return eOdds(prob);
    }

    const pool=[
      {code:'ov15',name:'Mas de 1.5 goles',prob:pOv15c,tier:0,group:'over'},
      {code:'un45',name:'Menos de 4.5 goles',prob:pUn45c,tier:0,group:'under'},
      {code:'dc1x',name:'DC '+t1d+'/Emp',prob:p1x,tier:0,group:'dc'},
      {code:'dcx2',name:'DC '+t2d+'/Emp',prob:px2,tier:0,group:'dc'},
      {code:'dc12',name:'DC Sin Empate',prob:p12,tier:0,group:'dc'},
      {code:'ts1',name:t1d+' anota',prob:pT1ov,tier:0,group:'ts1'},
      {code:'ts2',name:t2d+' anota',prob:pT2ov,tier:0,group:'ts2'},
      {code:'ov25',name:'Mas de 2.5 goles',prob:pOv25,tier:1,group:'over'},
      {code:'un35',name:'Menos de 3.5 goles',prob:pUn35c,tier:1,group:'under'},
      {code:'btts',name:'Ambos anotan Si',prob:pBtts,tier:1,group:'btts'},
      {code:'nobtts',name:'Ambos anotan No',prob:1-pBtts,tier:1,group:'btts'},
      {code:'favwin',name:favWinName,prob:favWinProb,tier:1,group:'win'},
      {code:'dnb',name:dnbFavName,prob:dnbFavProb,tier:1,group:'dnb'},
    ].map(c=>({...c,odds:bestOddsForPick(c.code,c.prob)})).filter(c=>c.prob>=0.55&&c.odds>=1.08).sort((a,b)=>a.tier!==b.tier?a.tier-b.tier:b.prob-a.prob);

    const CRR={'favwin+ts1':0.55,'favwin+ts2':-0.30,'favwin+btts':-0.15,'favwin+nobtts':0.20,'favwin+ov15':0.25,'favwin+ov25':0.15,'favwin+dc12':0.65,'favwin+dnb':0.55,'ov15+ov25':0.80,'ov15+btts':0.40,'ov15+ts1':0.35,'ov15+ts2':0.30,'ov15+un45':0.50,'ov25+btts':0.50,'ov25+ts1':0.25,'ov25+ts2':0.25,'un35+un45':0.70,'btts+ts1':0.65,'btts+ts2':0.65,'ts1+ts2':0.10,'dc12+dnb':0.55,'dnb+ts1':0.45,'dnb+ov15':0.20};
    function crr(c1,c2){return CRR[[c1,c2].sort().join('+')]||0;}
    function adjJoint(picks){if(!picks.length)return 1;let joint=picks[0].prob;for(let i=1;i<picks.length;i++){const avgC=picks.slice(0,i).reduce((s,p)=>s+crr(p.code,picks[i].code),0)/i;joint*=Math.max(0.02,Math.min(0.99,picks[i].prob*(1+avgC*0.35)));}return joint;}
    function conflicts(combo,cand){
      if(combo.some(c=>c.group===cand.group))return true;
      if((cand.code==='ov25'&&combo.some(c=>c.code==='un35'))||(cand.code==='un35'&&combo.some(c=>c.code==='ov25')))return true;
      return false;
    }

    // Armar combo inicial (max 4 picks o hasta x2)
    let combo=[],comboOdds=1.0;
    for(const cand of pool){
      if(combo.length>=4||comboOdds>=2.0)break;
      if(conflicts(combo,cand))continue;
      combo.push(cand);
      comboOdds*=cand.odds;
    }

    // === NUEVO: Si no llega a x2.0, agregar una pata mas del pool ===
    let piernExtra=null;
    if(comboOdds<2.0&&combo.length<5){
      const target=2.0/comboOdds;
      const remaining=pool.filter(c=>!combo.includes(c)&&!conflicts(combo,c)&&c.prob>=0.52);
      // Ordenar: primero los que alcanzan el target, luego por probabilidad
      remaining.sort((a,b)=>{
        const aOk=a.odds>=target, bOk=b.odds>=target;
        if(aOk&&!bOk)return -1;
        if(!aOk&&bOk)return 1;
        return b.prob-a.prob;
      });
      if(remaining.length>0){
        piernExtra=remaining[0];
        combo.push(piernExtra);
        comboOdds*=piernExtra.odds;
      }
    }

    // === NUEVO: Revisar cada bookmaker y ver cuales pagan x2+ con este combo ===
    const casasX2=[];
    if(oddsEvent&&combo.length>0){
      for(const bk of (oddsEvent.bookmakers||[])){
        let bkProd=1.0;
        for(const pick of combo){
          let bkPrice=null;
          for(const mkt of (bk.markets||[])){
            if(pick.code==='favwin'&&mkt.key==='h2h'){
              const tN=isFav1?team1Raw:team2Raw;
              const o=mkt.outcomes?.find(x=>nameMatch(x.name,tN));
              if(o?.price>1.01)bkPrice=o.price;
            } else if(pick.code==='ov15'&&mkt.key==='totals'){
              const o=mkt.outcomes?.find(x=>x.name==='Over'&&Math.abs((x.point||2.5)-1.5)<0.1);
              if(o?.price>1.01)bkPrice=o.price;
            } else if(pick.code==='ov25'&&mkt.key==='totals'){
              const o=mkt.outcomes?.find(x=>x.name==='Over'&&Math.abs((x.point||2.5)-2.5)<0.1);
              if(o?.price>1.01)bkPrice=o.price;
            } else if(pick.code==='dc12'&&mkt.key==='doubleChance'){
              const o=mkt.outcomes?.find(x=>x.name==='12');
              if(o?.price>1.01)bkPrice=o.price;
            } else if((pick.code==='ts1'||pick.code==='ts2')&&mkt.key==='h2h'){
              // ts1/ts2 no tiene mercado directo — usar odds sintetico
              bkPrice=null;
            }
          }
          bkProd*=bkPrice??pick.odds;
        }
        if(bkProd>=1.98){
          casasX2.push({name:bk.title||bk.key,odds:+bkProd.toFixed(2)});
        }
      }
      casasX2.sort((a,b)=>b.odds-a.odds);
    }

    const jointP=adjJoint(combo);
    const ev=jointP*(comboOdds-1)-(1-jointP);
    const reached=comboOdds>=2.0;
    const modCount=combo.filter(c=>c.tier===1).length;
    const riskLabel=modCount===0?'Bajo':modCount===1?'Bajo-Moderado':'Moderado';
    const evStr=(ev>=0?'+':'')+(ev*100).toFixed(1)+'%';

    if(!combo.length){
      msg=header+'No hay picks con confianza suficiente hoy.';
    } else {
      const rows=combo.map((c,i)=>(i+1)+'. '+c.name+' ['+pct(c.prob)+'] x'+c.odds.toFixed(2)).join('\n');

      // Linea de casas que pagan x2
      let casaLine='';
      if(casasX2.length>0){
        casaLine='\n✅ Casas que pagan x2+: '+casasX2.slice(0,4).map(c=>c.name+' (x'+c.odds+')').join(' | ');
      } else if(combo.some(c=>['ts1','ts2','cor','un45'].includes(c.code))){
        casaLine='\n⚠️ Incluye mercados sin cotizacion directa (estimado)';
      } else {
        casaLine='\n⚠️ Verificar cuotas exactas en tu casa';
      }

      // Linea de pata extra
      const piernLine=piernExtra?'\n➕ Pata extra agregada para alcanzar x2':'';

      msg=header+'---\n'+rows+'\n---\n'
        +'Cuota combinada: x'+comboOdds.toFixed(2)+(reached?' ✅':'')+'\n'
        +'Prob. ajustada: '+pct(jointP)+'\n'
        +'EV: '+evStr+' | Riesgo: '+riskLabel
        +casaLine+piernLine
        +'\n---\nxG: '+xg1.toFixed(2)+' - '+xg2.toFixed(2)+' '+src;
    }
    break;
  }
  default:
    msg = header + 'Mercado no disponible.';
}

return [{ json: { chatId, predMsg: msg } }];

