// 2) Fallback: openfootball schedule
let fbButtons = [];
let fbMsg = '';
try {
  const resp = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://raw.githubusercontent.com/openfootball/worldcup.json/master/2026/worldcup.json'
  });
  const matches = resp?.matches || [];
  const now = Date.now();

  const inProgress = matches.filter(m => {
    if (!m.date || !m.time) return false;
    const start = new Date(m.date + 'T' + m.time + ':00Z').getTime();
    const elapsed = (now - start) / 60000;
    return elapsed >= 0 && elapsed <= 115;
  });

  if (inProgress.length > 0) {
    fbButtons = inProgress.map(m => {
      const t1 = typeof m.team1==='string'?m.team1:(m.team1?.name||'?');
      const t2 = typeof m.team2==='string'?m.team2:(m.team2?.name||'?');
      // Score from openfootball (may be null during live)
      const g1 = m.score?.ft?.[0] ?? 0;
      const g2 = m.score?.ft?.[1] ?? 0;
      const startMs = new Date(m.date + 'T' + m.time + ':00Z').getTime();
      const elapsedMin = Math.min(90, Math.round((now - startMs) / 60000));
      const st = elapsedMin <= 45 ? '1H' : 'HT';
      // vvn: = openfootball fallback (no AF fixture ID)
      const cb = 'vvn:'+t1+'|'+t2+'|'+g1+'|'+g2+'|'+elapsedMin+'|'+st;
      return [{ text: '📡 '+t1+' '+g1+'-'+g2+' '+t2+' ('+elapsedMin+'\')', callback_data: cb }];
    });
    return [{ json: { chatId, menuText: '🔴 Partidos WC 2026 en vivo (estimado)\n📡 Datos de schedule — selecciona para predicción:', reply_markup: { inline_keyboard: fbButtons } } }];
  }

  const upcoming = matches.filter(m => {
    if (!m.date || !m.time) return false;
    const start = new Date(m.date + 'T' + m.time + ':00Z').getTime();
    return start > now;
  }).sort((a, b) => new Date(a.date+'T'+a.time+':00Z') - new Date(b.date+'T'+b.time+':00Z'));

  if (upcoming.length > 0) {
    const nx = upcoming[0];
    const t1 = typeof nx.team1==='string'?nx.team1:(nx.team1?.name||'?');
    const t2 = typeof nx.team2==='string'?nx.team2:(nx.team2?.name||'?');
    const start = new Date(nx.date+'T'+nx.time+':00Z');
    const minsLeft = Math.round((start.getTime()-now)/60000);
    fbMsg = '\n\n🕐 Próximo: '+t1+' vs '+t2+' — en '+minsLeft+' min';
    if (upcoming.length > 1) fbMsg += '\n(+' + (upcoming.length-1) + ' partidos más hoy)';
  }
} catch(e) { fbMsg = ''; }

const msg = '⚽ No hay partidos WC 2026 detectados en vivo ahora.' + fbMsg + '\n\nUsa /partidos para el calendario o /mercados para predicciones.';
return [{ json: { chatId, noLive: true, menuText: msg, reply_markup: null } }];

