  ];
}

// ── 3. Datos del partido ──────────────────────────────────────────────────
const home = fx.teams?.home?.name || 'Local';
const away = fx.teams?.away?.name || 'Visitante';
const gh = fx.goals?.home ?? 0;
const ga = fx.goals?.away ?? 0;
const elapsed = fx.fixture?.status?.elapsed || 0;
const statusShort = fx.fixture?.status?.short || '2H';
const isET = ['ET', 'P'].includes(statusShort);
const totalMin = isET ? 120 : 90;
const minutesLeft = Math.max(1, totalMin - elapsed);
const timeRatio = minutesLeft / 90;

// ── 4. ELO base ───────────────────────────────────────────────────────────
const ELO = {
  'argentina':2095,'france':1820,'brazil':1850,'england':1780,'spain':1790,
  'germany':1760,'netherlands':1740,'portugal':1750,'belgium':1710,'croatia':1670,
  'uruguay':1680,'denmark':1660,'switzerland':1650,'mexico':1630,'usa':1620,
  'united states':1620,'senegal':1620,'morocco':1640,'japan':1610,'colombia':1610,
  'south korea':1590,'sweden':1620,'ukraine':1590,'austria':1820,'poland':1600,
  'canada':1580,'australia':1560,'ecuador':1570,'nigeria':1580,'egypt':1570,
  'italy':1700,'norway':1650,'saudi arabia':1530,'qatar':1510,'turkey':1600
};
function getElo(name) {
  const k = (name||'').toLowerCase().replace(/[^a-z ]/g,'');
  if (ELO[k]) return ELO[k];
  for (const [key,val] of Object.entries(ELO))
    if (k.includes(key.substring(0,5))||key.includes(k.substring(0,5))) return val;
  return 1550;
}
const elo1 = getElo(home), elo2 = getElo(away);
const diff = elo1 - elo2;
const WC_AVG = 1.18;
const baseXG1 = Math.max(0.3, WC_AVG*(1+diff/700));
const baseXG2 = Math.max(0.3, WC_AVG*(1-diff/700));

let xgR1 = baseXG1 * timeRatio;
let xgR2 = baseXG2 * timeRatio;

const scoreDiff = gh - ga;
const DESP = 0.30, PARK = 0.15;
if (scoreDiff < 0) {
  xgR1 *= (1+Math.min(0.6,Math.abs(scoreDiff)*DESP));
  xgR2 *= (1-Math.min(0.25,Math.abs(scoreDiff)*PARK));
} else if (scoreDiff > 0) {
  xgR2 *= (1+Math.min(0.6,scoreDiff*DESP));
  xgR1 *= (1-Math.min(0.25,scoreDiff*PARK));
}

// ── FASE 3: Ajustar xG con estadísticas reales (tiros al arco) ───────────
// Blend 60% ELO + 40% datos reales del partido
let statsAdjNote = '';
if (Array.isArray(fx.statistics) && fx.statistics.length >= 2) {
  const homeId = fx.teams?.home?.id;
  const awayId = fx.teams?.away?.id;
  const statsH = fx.statistics.find(s => s.team?.id === homeId || s.team?.name === home);
  const statsA = fx.statistics.find(s => s.team?.id === awayId || s.team?.name === away);
  if (statsH && statsA) {
    const soTH = parseInt(statsH.statistics?.find(s=>s.type==='Shots on Goal')?.value || 0);
    const soTA = parseInt(statsA.statistics?.find(s=>s.type==='Shots on Goal')?.value || 0);
    const totalSoT = soTH + soTA;
    if (totalSoT >= 4) {
      const expectedRatio = xgR1 / (xgR1 + xgR2);
      const observedRatio = soTH / totalSoT;
      const blendedRatio = 0.6 * expectedRatio + 0.4 * observedRatio;
      const totalXgR = xgR1 + xgR2;
      const xgR1_prev = xgR1;
      xgR1 = Math.max(0.05, totalXgR * blendedRatio);
      xgR2 = Math.max(0.05, totalXgR * (1 - blendedRatio));
      const delta = xgR1 - xgR1_prev;
      if (Math.abs(delta) > 0.02) {
        statsAdjNote = `📊 ${soTH}-${soTA} tiros al arco → xG ajustado ${delta>0?'+':''}${delta.toFixed(2)}`;
      }
    }
  }
}

// ── 5. FACTOR ESTRELLA ────────────────────────────────────────────────────
let starWarn = '';
let starFactorH = 1.0, starFactorA = 1.0;
const homeNorm = home.toLowerCase().replace(/[^a-z]/g,'');
const awayNorm = away.toLowerCase().replace(/[^a-z]/g,'');
for (const est of estrellas) {
  const eqNorm = (est.equipo||'').toLowerCase().replace(/[^a-z]/g,'');
  const onHome = homeNorm.includes(eqNorm)||eqNorm.includes(homeNorm.substring(0,5));
  const onAway = awayNorm.includes(eqNorm)||eqNorm.includes(awayNorm.substring(0,5));
  if (onHome && est.factor_gol > starFactorH) {
    starFactorH = est.factor_gol;
    starWarn += `⚡ ${est.nombre} en cancha → incertidumbre elevada\n`;
  }
  if (onAway && est.factor_gol > starFactorA) {
    starFactorA = est.factor_gol;
    starWarn += `⚡ ${est.nombre} en cancha → incertidumbre elevada\n`;
  }
}
const lateGameMultiplier = elapsed >= 75 ? 1.4 : (elapsed >= 60 ? 1.2 : 1.0);
xgR1 *= Math.pow(starFactorH, 0.4) * (starFactorH > 1 ? lateGameMultiplier : 1);
xgR2 *= Math.pow(starFactorA, 0.4) * (starFactorA > 1 ? lateGameMultiplier : 1);
xgR1 = Math.min(xgR1, 1.8);
xgR2 = Math.min(xgR2, 1.8);

// ── 6. Modelo Poisson ─────────────────────────────────────────────────────
function poisson(lambda, k) {
  if (lambda <= 0) return k === 0 ? 1 : 0;
  let r = Math.exp(-lambda);
  for (let i = 1; i <= k; i++) r *= lambda / i;
  return Math.max(0, r);
}

let pHW=0, pD=0, pAW=0;
for (let h=0;h<=7;h++) for (let a=0;a<=7;a++) {
  const p = poisson(xgR1,h)*poisson(xgR2,a);
  const fh=gh+h, fa=ga+a;
  if (fh>fa) pHW+=p; else if (fh===fa) pD+=p; else pAW+=p;
}
const tot=pHW+pD+pAW; pHW/=tot; pD/=tot; pAW/=tot;

const curTotal=gh+ga;
let pOv25=0;
if (curTotal>=3) { pOv25=1.0; } else {
  const need=3-curTotal;
  for (let h=0;h<=6;h++) for (let a=0;a<=6;a++)
    if (h+a>=need) pOv25+=poisson(xgR1,h)*poisson(xgR2,a);
}
pOv25=Math.min(1,pOv25);

const pHScores = 1-Math.exp(-xgR1);
const pAScores = 1-Math.exp(-xgR2);
const pNoMore  = Math.exp(-xgR1)*Math.exp(-xgR2);
let pBtts;
if (gh>0&&ga>0) pBtts=1.0;
else if (gh>0) pBtts=pAScores;
else if (ga>0) pBtts=pHScores;
else pBtts=pHScores*pAScores;

const pNextH = xgR1/(xgR1+xgR2);
const pNextA = xgR2/(xgR1+xgR2);

// ── 7. Aplicar calibración aprendida ─────────────────────────────────────
const pNoMoreC = Math.max(0, Math.min(1, pNoMore  * cf.sin_goles));
const pBttsC   = Math.max(0, Math.min(1, pBtts   * cf.btts));
const pOv25C   = Math.max(0, Math.min(1, pOv25   * cf.mas25));
const raw1x2sum = pHW*cf['1x2'] + pD + pAW*cf['1x2'];
const pHWC = pHW*cf['1x2']/raw1x2sum;
const pDC  = pD/raw1x2sum;
const pAWC = pAW*cf['1x2']/raw1x2sum;

// ── 8. Guardar predicción para aprendizaje ────────────────────────────────
const partidoKey = home+'|'+away+'|'+(fx.fixture?.date||'').substring(0,10);
try {
  await $helpers.httpRequest({
    method: 'POST',
    url: SB_URL + '/rest/v1/log_predicciones_live',
    headers: { ...SB_H, 'Content-Type':'application/json', Prefer:'return=minimal' },
    body: JSON.stringify({
      partido_key: partidoKey,
      equipo1: home, equipo2: away, liga: 'WC2026',
      minuto: elapsed, tiempo: statusShort,
      goles1: gh, goles2: ga,
      prob_local:    +pHWC.toFixed(4),
      prob_empate:   +pDC.toFixed(4),
      prob_visita:   +pAWC.toFixed(4),
      prob_sin_goles:+pNoMoreC.toFixed(4),
      prob_btts:     +pBttsC.toFixed(4),
      prob_mas25:    +pOv25C.toFixed(4),
      prob_next_local: +pNextH.toFixed(4),
      prob_next_visit: +pNextA.toFixed(4)
    })
  });
} catch(e) {}

// ── FASE 2: Combo multi-partido (independencia válida entre partidos) ──────
// REGLA: solo combinamos mercados de partidos DISTINTOS → P(A∩B) = P(A)×P(B)
// φ≈0 entre partidos distintos → sin doble conteo → EV real
let comboMsg = '';
try {
  const recentPreds = await $helpers.httpRequest({
    method: 'GET',
    url: SB_URL + '/rest/v1/log_predicciones_live?select=equipo1,equipo2,minuto,prob_local,prob_visita,prob_sin_goles&order=id.desc&limit=30',
    headers: SB_H
  });

  if (Array.isArray(recentPreds) && recentPreds.length > 1) {
    const homeQ = home.toLowerCase().substring(0,6);
    const awayQ = away.toLowerCase().substring(0,6);

    // Deduplicar: solo la predicción más reciente de cada partido distinto
    const byMatch = new Map();
    for (const p of recentPreds) {
      const e1 = (p.equipo1||'').toLowerCase();
      const e2 = (p.equipo2||'').toLowerCase();
      const esDiferente = !e1.includes(homeQ) && !e2.includes(homeQ) &&
                          !e1.includes(awayQ) && !e2.includes(awayQ);
      const k = p.equipo1 + '|' + p.equipo2;
      if (esDiferente && p.minuto >= 15 && !byMatch.has(k)) {
        byMatch.set(k, p);
      }
    }

    // Mejor pick de cada partido distinto
    const otroPicks = [];
    for (const [, p] of byMatch) {
      const cands = [
        { prob: p.prob_sin_goles || 0, label: 'Sin más goles', icon: '🔒' },
        { prob: p.prob_local || 0,     label: `${p.equipo1} gana`, icon: '🏠' },
        { prob: p.prob_visita || 0,    label: `${p.equipo2} gana`, icon: '✈️' },
      ].filter(c => c.prob >= 0.65).sort((a,b) => b.prob - a.prob);
      if (cands.length > 0) {
        otroPicks.push({
          match: `${p.equipo1} vs ${p.equipo2}`,
          ...cands[0],
          minuto: p.minuto
        });
      }
    }

    // Mejor pick del partido actual (solo 1, el más fuerte)
    const myPick = [
      { prob: pNoMoreC, label: 'Sin más goles', icon: '🔒', valid: elapsed >= 60 && pNoMoreC >= 0.65 },
      { prob: pHWC,     label: `${home} gana`,  icon: '🏠', valid: pHWC >= 0.75 },
      { prob: pAWC,     label: `${away} gana`,  icon: '✈️', valid: pAWC >= 0.75 },
    ].filter(c => c.valid).sort((a,b) => b.prob - a.prob)[0];

    if (myPick && otroPicks.length > 0) {
      const combosValidos = [];
      for (const otro of otroPicks.slice(0,5)) {
        const probCombo = myPick.prob * otro.prob;
        if (probCombo >= 0.45) {
          combosValidos.push({
            pick1: { match: `${home} vs ${away}`, ...myPick, minuto: elapsed },
            pick2: otro,
            probCombo: +(probCombo*100).toFixed(1),
            cuotaMin: +(1/probCombo).toFixed(2)
          });
        }
      }
      combosValidos.sort((a,b) => b.probCombo - a.probCombo);

      if (combosValidos.length > 0) {
        const best = combosValidos[0];
        comboMsg = '\n━━━━━━━━━━━━━━━━━━━━\n';
        comboMsg += '🔥 LIVE COMBO SUGERIDO:\n';
        comboMsg += `(partidos independientes = sin doble conteo)\n\n`;
        comboMsg += `${best.pick1.icon} ${best.pick1.match} (min ${best.pick1.minuto})\n`;
        comboMsg += `   → ${best.pick1.label}: ${(best.pick1.prob*100).toFixed(1)}%\n\n`;
        comboMsg += `${best.pick2.icon} ${best.pick2.match} (min ${best.pick2.minuto})\n`;
        comboMsg += `   → ${best.pick2.label}: ${(best.pick2.prob*100).toFixed(1)}%\n\n`;
        comboMsg += `Prob. combinada: ${best.probCombo}%\n`;
        comboMsg += `Cuota mínima para ventaja: ${best.cuotaMin}x\n`;
        comboMsg += `⚠️ Solo apuesta si encuentras ≥ ${best.cuotaMin}x`;
      }
    }
  }
} catch(e) {}

// ── 10. Construir mensaje ─────────────────────────────────────────────────
function pct(p) { return (Math.min(1,Math.max(0,p))*100).toFixed(1)+'%'; }

const stMap = {'1H':'1er Tiempo','HT':'DESCANSO','2H':'2do Tiempo','ET':'Prorroga','P':'Penales'};
const stLabel = stMap[statusShort]||statusShort;
const favFinal = pHWC>pAWC&&pHWC>pDC ? home : (pAWC>pHWC&&pAWC>pDC ? away : 'Empate');
const urgency = Math.abs(scoreDiff)>=2?' (remontada muy dificil)':(Math.abs(scoreDiff)===1?' (un gol lo cambia todo)':'');

const statsBlock = (fx.statistics||[]).map(ts => {
  const team = ts.team?.name||'?';
  const shots = ts.statistics?.find(s=>s.type==='Shots on Goal')?.value||0;
  const poss  = ts.statistics?.find(s=>s.type==='Ball Possession')?.value||'?';
  return team+': '+shots+' tiros | '+poss+' posesion';
}).join('\n');

const confianzaFlag = starWarn ?
  `\n⚠️ JUGADOR ESTRELLA ACTIVO:\n${starWarn}(Prob ajustadas — puede superar la estadística)` : '';
const noGoalWarning = (pNoMoreC > 0.90 && starWarn) ?
  '\n🎯 Sin goles alto PERO estrella activa: puede romperla en cualquier momento' : '';

const lines = [
  'PREDICCION EN VIVO | WC 2026',
  `${home} ${gh} - ${ga} ${away}`,
  `Min ${elapsed} | ${stLabel} | ${minutesLeft} min restantes${urgency}`,
  '',
  'RESULTADO FINAL ACTUALIZADO:',
  `${home} gana: ${pct(pHWC)}`,
  `Empate: ${pct(pDC)}`,
  `${away} gana: ${pct(pAWC)}`,
  `Pronóstico: ${favFinal}`,
  '',
  'MERCADOS EN VIVO:',
  `Más de 2.5 goles: ${pct(pOv25C)}${curTotal>=3?' ✅ CUMPLIDO':''}`,
  `Ambos anotan (BTTS): ${pct(pBttsC)}${gh>0&&ga>0?' ✅ CUMPLIDO':''}`,
  `Sin más goles (cierre): ${pct(pNoMoreC)}`,
  `Siguiente gol ${home}: ${pct(pNextH)}`,
  `Siguiente gol ${away}: ${pct(pNextA)}`,
  '',
  statsBlock ? `STATS LIVE:\n${statsBlock}` : '',
  statsAdjNote || '',
  '',
  `ELO: ${home} ${elo1} | ${away} ${elo2}`,
  `xG restante: ${home} ${xgR1.toFixed(2)} | ${away} ${xgR2.toFixed(2)}`,
  scoreDiff!==0 ? `Ajuste marcador: ${scoreDiff<0?home:away} empuja +30% xG` : 'Partido igualado',
  confianzaFlag,
  noGoalWarning,
  comboMsg
].filter(Boolean).join('\n');

return [{ json: { chatId, predMsg: lines.substring(0,4000) } }];

const item = $input.first()?.json || {};
const chatId = $('Parse Callback').first()?.json?.chatId || item.chatId || '';
let output = item.output || '';
if (!output || output.trim().length < 10) {
  return [{ json: { chatId, output: 'No pude procesar el analisis ahora. Intenta de nuevo en un momento.' } }];
}
const MAX = 4000;
if (output.length <= MAX) {
  return [{ json: { chatId, output } }];
}
// Dividir en partes en saltos de línea naturales
const parts = [];
while (output.length > 0) {
  if (output.length <= MAX) { parts.push(output); break; }
  let cut = output.lastIndexOf('\n', MAX);
  if (cut < 500) cut = MAX;
  parts.push(output.substring(0, cut).trim());
  output = output.substring(cut).trim();
}
return parts.map(p => ({ json: { chatId, output: p } }));
